prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?path) AS ?executionWays) WHERE {
  {
    SELECT DISTINCT ?path WHERE {
      ?model a bboExt:Model .
      FILTER(tai:normalizedId = "fbb0adafe6924f58ac902063a36646fe")
      ?model tai:belongsTo ?org .
      ?defs tai:belongsTo ?model .
      ?choreo tai:belongsTo ?defs .

      ?start a bboExt:StartEvent ; bbo:name ?startName .
      ?start tai:belongsTo ?choreo .

      # Build a simple execution trace from start to end following sequence flows.
      # Each distinct set of traversed edges represents a different path.
      {
        SELECT DISTINCT ?path WHERE {
          ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?end .
          ?end a bboExt:EndEvent .
          ?end tai:belongsTo ?choreo .

          # Collect visited nodes to identify path uniquely.
          BIND(CONCAT(
            STR(?start), "->", STR(?end)
          ) AS ?path)
        }
        LIMIT 10000
      }
    }
  }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?modelName ?choreo ?choreoName ?startCount ?endCount WHERE {
  ?model a bboExt:Model .
  FILTER(tai:normalizedId = "fbb0adafe6924f58ac902063a36646fe")
  OPTIONAL { ?model bbo:name ?modelName . }

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  {
    SELECT (COUNT(DISTINCT ?s) AS ?startCount) WHERE {
      ?s a bboExt:StartEvent ; tai:belongsTo ?choreo .
    }
  }
  {
    SELECT (COUNT(DISTINCT ?e) AS ?endCount) WHERE {
      ?e a bboExt:EndEvent ; tai:belongsTo ?choreo .
    }
  }
}
ORDER BY ?choreoName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId ?orgId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:belongsTo ?org .
             ?org tai:organizationId ?orgId . }
  FILTER(
    (BOUND(?origId) && ?origId = "fbb0adafe6924f58ac902063a36646fe") ||
    (BOUND(?normId) && ?normId = "fbb0adafe6924f58ac902063a36646fe")
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName ?defs ?defsHas WHERE {
  ?model a bboExt:Model ; tai:normalizedId "sid_e0cff846_e631_4657_9d55_ab4c98968cd7" .

  OPTIONAL {
    ?defs tai:belongsTo ?model .
    OPTIONAL { ?defs bbo:name ?defsHas . }
  }

  # Try both: choreography directly in definitions or directly in model
  OPTIONAL {
    ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
    OPTIONAL { ?choreo bbo:name ?choreoName . }
  }

  OPTIONAL {
    ?choreo a bboExt:Choreography ; tai:belongsTo ?model .
    OPTIONAL { ?choreo bbo:name ?choreoName . }
  }
}
LIMIT 25
